"use strict";(self.webpackChunksentinel_docs=self.webpackChunksentinel_docs||[]).push([[2576],{13050:e=>{e.exports=JSON.parse('{"version":{"pluginId":"sdk","version":"current","label":"Next","banner":null,"badge":false,"noIndex":false,"className":"docs-version-current","isLast":true,"docsSidebars":{"tutorialSidebar":[{"type":"link","href":"/sdk/","label":"\ud83d\udcd8 Overview","docId":"README","unlisted":false},{"type":"link","href":"/sdk/golang","label":"\ud83d\udd27 Golang","docId":"golang","unlisted":false},{"type":"link","href":"/sdk/javascript","label":"\ud83d\udce6 Javascript","docId":"javascript","unlisted":false},{"type":"link","href":"/sdk/python","label":"\ud83d\udc0d Python","docId":"python","unlisted":false}]},"docs":{"golang":{"id":"golang","title":"Golang","description":"The Go SDK is the most complete of the three - it covers the full stack from blockchain client operations down to native VPN tunnel management. Built on Cosmos SDK and CometBFT, it provides everything needed to query chain state, sign transactions, communicate with nodes, and run WireGuard, V2Ray, or OpenVPN tunnels. This is the SDK used by node operators and service builders.","sidebar":"tutorialSidebar"},"javascript":{"id":"javascript","title":"Javascript","description":"The JavaScript SDK lets you interact with the Sentinel blockchain from any browser or Node.js environment. It extends CosmJS, the standard JavaScript library for Cosmos chains - adding Sentinel-specific queries, transactions, and VPN session management on top. If you\'ve worked with CosmJS before, you\'ll feel right at home.","sidebar":"tutorialSidebar"},"python":{"id":"python","title":"Python","description":"The Python SDK provides a straightforward way to query the Sentinel blockchain, manage subscriptions, and handle VPN sessions from Python. It talks to the chain over gRPC using sentinel-protobuf for message definitions and mospy for transaction signing. It\'s a good fit for scripting, automation, and building backend services that need to interact with Sentinel nodes.","sidebar":"tutorialSidebar"},"README":{"id":"README","title":"Overview","description":"Three SDKs are available for building on Sentinel. Each one covers a different language and use case, but they all let you query chain state, manage subscriptions and sessions, and connect to dVPN nodes.","sidebar":"tutorialSidebar"}}}}')}}]);